@ARTICLE{10.20368/1971-8829/1135893,
	author = {Vo, D.V. and Thien Nguyen, P.N. and Power, J.},
	title = {Online learning readiness in secondary education: validating the Online Learning Readiness Scale and examining the impact role of ICT familiarity},
	journal = {Journal of E-Learning and Knowledge Society},
	year = {2024},
	abstract = {Online and blended learning have increased drastically during the pandemic, and their popularity has persisted as we emerge from this global crisis. This study aims to adapt and validate the Online Learning Readiness Scale (OLRS) to assess high school students. Secondary school students were recruited (n = 296) for the study. The OLRS scale included five components: Technology Readiness, Learner Control, Online Communication Self-efficacy, Self-directed Learning and Motivation for Learning. Results supported the OLRS scale in terms of reliability and internal construct validity in context of the study by confirmatory factor analysis and Rasch measurement with partial credit analysis. The differential item functioning analysis revealed no bias issues regarding gender, confirming the measurement invariance statistics achieved. The study also found that the majority of students (73.7%) engaged in online learning solely through their mobile phone. ICT familiarity, i.e., interacting with friends regularly, browsing online learning materials, and watching educational videos on YouTube, had a positive association with students’ readiness for online learning. Students’ access to social networks, online forums and online music did not have a significant effect on their readiness for online learning. The scale demonstrated the capacity to function as an assessment instrument for evaluating readiness for online learning in the context of secondary education. Educational implications were considered, including key requirements of supporting technology and pedagogical practice in online and blended learning environments. © Italian e-Learning Association. ER -},
	doi = {10.20368/1971-8829/1135893},
	type = {JOUR}
}

@ARTICLE{10.1515/nleng-2022-0300,
	author = {Liu, R.},
	title = {Analysis of multimedia technology and mobile learning in English teaching in colleges and universities},
	journal = {Nonlinear Engineering},
	year = {2023},
	abstract = {Multimedia and mobile learning are effective teaching tools because of their many useful characteristics. Transmission of educational material to students is facilitated by technology in both multimedia and mobile learning environments. A more interesting and engaging learning experience may be achieved by combining text, graphics, music, video, and animation. Media-rich classrooms are often referred to as "multimedia learning."In contrast, students who use mobile learning may access their courses from any place with an internet connection and a mobile device such as a smartphone or a tablet. Whenever this involves commonplace technological needs, its cellular gadget and notably its clever telephone take the cake. Smartphone gadgets have a very wide range of potential applications and uses. Some ethical considerations are preventing media from reinforcing stereotypes or prejudice in the communities where they are utilized. Student information are gathered and used in a way that protects their privacy, with materials required for students to engage in mobile learning, and respecting intellectual property and copyright regulations while using multimedia language-learning tools. This importance of learning cannot be overstated but when such results come, mobile devices have increasingly been used in schools. This question of whether mobile devices have an impact on education remains open. Because of such "mobile gaining knowledge,"along with an overall phrase describing researching where different devices could be utilized in combination to enhance schooling, mobile devices had become more popular. Because today's kids utilize their mobile devices frequently, studies on their effect on word learning are immediately required. This pilot research seeks to understand why school learners think via smartphone-based L2 exercises. In particular, this study collects data about several plenty applications using cell phones in linguistic research. Two hundred and ninety-four college children from one top Turkish institution participated in this research. This project uses some hybrid reporting models and relies on description analysis over its methodology. Their results show that users place one high value on obtaining ready accessibility to materials while studying some foreign language. Respondents not only remarked about their cellphone's portability but also proposed new applications for enhancing their learning in other countries. © 2023 the author(s), published by De Gruyter. ER -},
	doi = {10.1515/nleng-2022-0300},
	type = {JOUR}
}

@ARTICLE{10.1002/jad.12173,
	author = {Li, B. and Gu, Y. and Yang, Y. and Zhao, M. and Dong, Y.},
	title = {The effect of problematic smartphone use on school engagement and disengagement among middle school students: The mediating role of academic procrastination and sleep quality},
	journal = {Journal of Adolescence},
	year = {2023},
	abstract = {Introduction: Although a few research have tried to explore the relationship between problematic smartphone use (PSU) and school engagement, most of them are limited to relatively simple correlation, and the mechanism needs to be further explored. This research focused on the relationship between PSU and school engagement/disengagement, and intended to verify two mediation paths. Methods: We conducted two studies in 2019 at a middle school in China. 289 students (44.6% girls), aged 11–18 (Mage = 13.25, standard deviation [SD] = 1.73), participated in Study 1, a longitudinal cross-lag analysis intend to verify the relationship between PSU and school engagement/disengagement. Using a separate sample, Study 2 explored the mediating roles of academic procrastination and sleep quality. Four hundred thirty-two students aged 11–19 (42.1% girls, Mage = 16.11, SD = 1.56) participated in this cross-sectional study. In both studies, all participants completed self-report measures in classrooms during regular school hours. Results: In Study 1, the results showed that PSU (T1) could significantly predict school engagement/disengagement (T2), but school engagement/disengagement (T1) could not predict PSU (T2). In Study 2, we found that academic procrastination could mediate the effect of PSU on school engagement, and sleep quality could mediate the effect of PSU on both school engagement and disengagement. Conclusions: Results highlighted that the school engagement/disengagement of adolescents can be influenced by PSU through several different ways, through which we can protect adolescents from the negative effects of PSU. © 2023 Foundation for Professionals in Services to Adolescents. ER -},
	doi = {10.1002/jad.12173},
	type = {JOUR}
}

@ARTICLE{10.1177/01614681241282175,
	author = {Yee, S.},
	title = {“A Change Is Gonna Come”: Pedagogical Shifts in a Post-COVID World},
	journal = {Teachers College Record},
	year = {2024},
	abstract = {Background/Context: COVID-19 changed how students learn, the challenges they face both in and out of the classroom, and the ways they access and engage with higher education. COVID-19 also highlighted inequalities in higher education. In response, faculty have also had to change their pedagogical approaches. Purpose/Focus of Study: This article presents ideas to address some of the challenges that COVID-19 has brought to the community college classroom. The focus of these strategies and pedagogical changes is to create a more equitable and successful environment for all students. Research Design: The author's praxis used Paulo Freire's 1970 work, The Pedagogy of the Oppressed, as a guide to critically examine pedagogical practices and choices for sociological curriculum development at a medium-sized, urban, Hispanic-serving community college. Changes were evaluated through final grade analysis and student feedback. Findings: Ten changes were implemented: making the course mobile phone/tablet accessible, incorporating audio transcripts for all, using additional video formats, engaging families/children, addressing student anxieties, incorporating more assignment choices, using Open Educational Resources for reduced costs, allowing more flexibility in assignments, extending submission times, and varying course length. These changes have reduced barriers, decreased student anxiety, and increased student success. Conclusions: The pedagogical changes made seemed to help students be more successful in their courses. © Teachers College 2024. ER -},
	doi = {10.1177/01614681241282175},
	type = {JOUR}
}

@ARTICLE{10.1080/09588221.2020.1799825,
	author = {Nazari, M. and Xodabande, I.},
	title = {L2 teachers’ mobile-related beliefs and practices: contributions of a professional development initiative},
	journal = {Computer Assisted Language Learning},
	year = {2022},
	abstract = {Mobile phones are turning into a growingly widespread educational tool across various contexts. However, the scope of research on teachers’ role in mobile-oriented instruction is limited, much less examining how professional development influences their associated beliefs and practices. Grounded in sociocultural theory, this study aimed to fill some of the void by exploring the contributions of a professional development initiative framed around mobile phone usage to L2 teachers’ beliefs and practices. Data were collected from semi-structured interviews, classroom observations, and online reflections. Data analyses indicated that the teachers gradually developed further awareness of educational exploitability of mobile phones and experienced restructuring in their associated beliefs. Additionally, the analysis of observational data showed direct and indirect patterns of utilizing mobiles by the teachers, undergoing changes during the research process. Results of the study offer implications for mobile-related teacher education, particularly professional development courses geared toward enhancing in teachers greater awareness of utilizing mobile devices. © 2020 Informa UK Limited, trading as Taylor & Francis Group. ER -},
	doi = {10.1080/09588221.2020.1799825},
	type = {JOUR}
}

@ARTICLE{10.1007/s11423-022-10149-1,
	author = {Huynh, T.-N. and Lin, C.-J. and Hwang, G.-J.},
	title = {Learner-generated material: the effects of ubiquitous photography on foreign language speaking performance},
	journal = {Educational Technology Research and Development},
	year = {2022},
	abstract = {The widespread availability of mobile phones has facilitated mobile learning and ubiquitous learning in language education. Although numerous benefits have been documented, the evidence for speaking fluency enhancement is relatively scant. Firmly grounded in humans’ cognitive structure and learners’ prior knowledge, this study proposes a ubiquitous photography strategy as a form of generative learning strategy. Specifically, besides the photos in English textbooks, foreign language (FL) learners at the college level were encouraged to use their mobile phones to capture photos to practice visual prompted oral tasks. Their learning experience was measured by a self-report questionnaire, triggering their perceptions of mental effort, task complexity, and learning preferences. Their learning outcome was measured by speech analysis of their oral performance, targeting fluency, and vocabulary diversity. Data analysis revealed that ubiquitous photography induced a better learning experience and enhanced their speaking outcomes to various extents. Results contribute to the potential of integrating ubiquitous learning and generative learning strategies in FL classrooms. © 2022, Association for Educational Communications and Technology. ER -},
	doi = {10.1007/s11423-022-10149-1},
	type = {JOUR}
}

@ARTICLE{10.17206/apjrece.2021.15.3.113,
	author = {Fauzi, W.J. and Radzuan, N.R.M. and Ngah, E. and Rani, A.A. and Ali, F.},
	title = {Digitising English Language Learning For Early Childhood Educators In Malaysian Context: The Rationale},
	journal = {Asia-Pacific Journal of Research in Early Childhood Education},
	year = {2021},
	abstract = {Nowadays, many kindergartens in Malaysia are striving toward using English in their daily activities with their children and some even use English language as their medium of instruction. However, some of the early childhood educators were not well equipped with the knowledge of English language. This paper aims to report the rationale for digitising English language learning through the development of Kindy Talk Application in terms of approach, content and design. Kindy Talk Application is a mobile application for Malaysian early childhood educators to utilise accurate language in their daily routine interactions and instructional language typically used at daycare centres. This development of the application stemmed from a series of workshops with 2 modules, namely Communication English and Storytelling techniques. These workshops aimed at increasing 30 Pahang early childhood educators’ professional development. To ensure the sustainability of the training, the Kindy Talk Application, which uses augmented reality technology was developed to allow users to practise the daily routine and instructional language using their mobile phones in a safe autonomous learning environment. This enhances the language proficiency and confidence of Malaysian early childhood educators. © 2021. Asia-Pacific Journal of Research in Early Childhood Education. All Rights Reserved. ER -},
	doi = {10.17206/apjrece.2021.15.3.113},
	type = {JOUR}
}

@ARTICLE{10.31729/jnma.8268,
	author = {Meena, P. and Mohanasundaram, S. and Kurian, J. and Prasad, G.S. and Bhargava, V. and Panda, S. and Agrawaal, K.K.},
	title = {Harnessing Social Media to Enhance Nephrology Academia},
	journal = {Journal of the Nepal Medical Association},
	year = {2023},
	abstract = {The process of learning has been confined to the realms of educational institutions. Over the last ten years, the semantics of social media networks have evolved with the use of mobile gadgets. Consequently, nephrologists have realised the potential benefits of using these platforms for their educational and career development. Social media can change the horizon of nephrology education. The concept of bedside examination, teaching and sharing experiences have changed with the advent of Facebook, YouTube, Instagram and X (former Twitter). Other networking portals, such as WhatsApp, Telegram, X (former Twitter), and Pinterest, have also amassed the attention of selected users. Despite split opinions on the utility of social media, it is undeniable that it has influenced interaction between students and mentors. Resources ranging from online networks, blogs, visual aids, podcasts, online journal clubs, videos, live conference coverages, and tutorials have made it possible for nephrologists to stay informed and educated with recent updates. In this review, we discuss how social media can enrich nephrology academia, facilitate the sharing of research and access to fellowships and mentorship programs, provide career prospects to trainees, and broadcast scientific conferences while bringing nephrology societies together. © 2023, Nepal Medical Association. All rights reserved. ER -},
	doi = {10.31729/jnma.8268},
	type = {JOUR}
}

@ARTICLE{10.14569/ijacsa.2021.0121136,
	author = {Ishaq, K. and Rosdi, F. and Zin, N.A.M. and Abid, A.},
	title = {Heuristics and Think-aloud Method for Evaluating the Usability of Game-based Language Learning},
	journal = {International Journal of Advanced Computer Science and Applications},
	year = {2021},
	abstract = {Digital learning environments are increasingly becoming popular in recent years. The rising usage of cell phones has invited researchers to design and develop learning applications and games for mobile phones. Specifically, gamebased language learning is being promoted by researchers in many parts of the world. “Language Learning Serious Game (LLSG)” is based on a theoretical model constructed by the researcher that supports children learning English as a second language in a cultural context. The usability of such games is evaluated based on well-defined heuristics and other standard methods. This research aims to appraise the usability of LLSG through heuristics and think-aloud approaches while involving all essential stakeholders, including language experts, students, teachers, and game developers. The researcher proposed the heuristics in a cultural context, whereas the think-aloud review is compiled from the rigorous discussion session involving these stakeholders to evaluate the LLSG. The findings obtained from the heuristics evaluation reveal that the usability of LLSG is acceptable. On the other hand, various interesting suggestions and reviews were gathered from the discussion between experts and students. This evaluation will further improve the future versions of the game. © 2021. All Rights Reserved. ER -},
	doi = {10.14569/ijacsa.2021.0121136},
	type = {JOUR}
}

@ARTICLE{10.1186/s12909-024-05029-6,
	author = {Atashinsadaf, A. and Ramezani-badr, F. and Long, T. and Imanipour, M. and Amini, K.},
	title = {Facilities, challenges, attitudes, and preferences of nursing students related to e-learning in the Covid-19 pandemic in Iranian context: a cross-sectional study},
	journal = {BMC Medical Education},
	year = {2024},
	abstract = {Background: During the Covid-19 pandemic, nursing schools worldwide were forced to deliver nursing courses in ways other than the traditional face-to-face classroom setting. Numerous lessons were learned by nurse educators regarding the use of electronic and online learning strategies. It is necessary to be aware of the factors affecting e-learning and identify the strengths and weaknesses to improve the student learning experience and process in nursing school. Aim of study: The present study aimed to identify the abilities, attitudes, challenges, and preferences of nursing students regarding e-learning during the Covid-19 pandemic. Recognition of these factors can help nurse educators make needed modifications to teach more effectively. Methods: In this cross-sectional study, 228 undergraduate nursing students participated. The random sampling method used a standard questionnaire that students completed voluntarily. SPSS version 22 was used for data analysis. Results: During the Covid-19 pandemic, the majority of nursing students of Zanjan University of Medical Sciences participated in electronic classes at home using mobile phones. Students reported that logistical problems increased by participating in e-classes by their phones due to difficulty typing and frequent internet outages. Online classroom management for instructors was difficult due to students spontaneously leaving the virtual online classroom rather than attending the entire learning session. Despite the technical challenges, the attitudes of students towards the e-learning format were positive. There was a noted correlation between student attitude by gender and educational background. Students preferred that professors used more PowerPoint, showed instructional videos, and had interactive group discussion sessions rather than lecture only. Students objected to attending more than two online classes in one day if the duration lasted more than 60 min and had a rest time of fewer than 30 min between classes. Conclusion: Despite the overall positive student satisfaction with e-learning, this method of education is still far from student preferences and requires planning for an effective learning experience that meets their priorities and preferences. Using a hybrid of face-to-face and e-learning approaches together can be a more effective teaching method than either strategy alone. © 2024, The Author(s). ER -},
	doi = {10.1186/s12909-024-05029-6},
	type = {JOUR}
}
